import { defineComponentSlotStyle } from "@yamada-ui/react"
import { getInputPaddingStartResetStyle, inputStyle } from "../input"

export const fileInputStyle = defineComponentSlotStyle({
  base: {
    root: {
      ...inputStyle.base,
      alignItems: "center",
      cursor: "pointer",
      display: "flex",
      flexWrap: "wrap",
      gapX: "1",
      lineHeight: "1",
      _readOnly: {
        layerStyle: "readOnly",
      },
    },
    tag: {
      display: "inline-block",
      overflow: "hidden",
      whiteSpace: "nowrap",
    },
  },

  variants: {
    filled: {
      root: inputStyle.variants?.filled,
    },
    flushed: {
      root: {
        ...inputStyle.variants?.flushed,
        ...getInputPaddingStartResetStyle(),
      },
    },
    outline: {
      root: inputStyle.variants?.outline,
    },
    plain: {
      root: inputStyle.variants?.plain,
    },
  },

  sizes: {
    xs: {
      root: { py: "{--space-y}", ...inputStyle.sizes?.xs },
    },
    sm: {
      root: { py: "{--space-y}", ...inputStyle.sizes?.sm },
    },
    md: {
      root: { py: "{--space-y}", ...inputStyle.sizes?.md },
    },
    lg: {
      root: { py: "{--space-y}", ...inputStyle.sizes?.lg },
    },
    xl: {
      root: { py: "{--space-y}", ...inputStyle.sizes?.xl },
    },
    "2xl": {
      root: { py: "{--space-y}", ...inputStyle.sizes?.["2xl"] },
    },
  },

  defaultProps: {
    size: "md",
    variant: "outline",
  },
})

export type FileInputStyle = typeof fileInputStyle

import { a11y, page, render } from "#test/browser"
import { FileInput } from "."
import { InputPropsContext } from "../input"

const getInput = () =>
  document.querySelector('input[type="file"]') as HTMLInputElement

const clickElement = (element: HTMLElement | SVGElement) => {
  if (!(element instanceof HTMLElement))
    throw new TypeError("Expected an HTML element")

  element.click()
}

const changeFiles = (files: File[] | null) => {
  const input = getInput()

  Object.defineProperty(input, "files", {
    configurable: true,
    value: files,
  })

  input.dispatchEvent(new Event("change", { bubbles: true }))
}

describe("<FileInput />", () => {
  test("renders component correctly", async () => {
    await a11y(
      <FileInput
        placeholder="placeholder"
        _placeholder={{ color: "black", opacity: 1 }}
      />,
    )
  })

  test("sets `displayName` correctly", () => {
    expect(FileInput.displayName).toBe("FileInputRoot")
  })

  test("sets `className` correctly", async () => {
    await render(<FileInput placeholder="placeholder" />)
    const el = page.getByText("placeholder").element()
    expect(el.parentElement).toHaveClass("ui-file-input__root")
  })

  test("renders HTML tag correctly", async () => {
    await render(<FileInput placeholder="placeholder" />)
    const el = page.getByText("placeholder").element()
    expect(el.parentElement?.tagName).toBe("DIV")
    expect(el.tagName).toBe("SPAN")
  })

  test("sets multiple attribute", async () => {
    await render(<FileInput multiple placeholder="multiple" />)
    expect(getInput()).toHaveAttribute("multiple")
  })

  test("should accept only provided file types", async () => {
    await render(
      <FileInput accept="image/png,image/jpeg" placeholder="only png, jpeg" />,
    )
    expect(getInput()).toHaveAttribute("accept", "image/png,image/jpeg")
  })

  test("should render files with provided separator", async () => {
    await render(<FileInput data-testid="fileInput" multiple separator=";" />)
    const file = new File(["foo"], "foo.txt", { type: "text/plain" })

    changeFiles([file, file])

    await expect
      .element(page.getByTestId("fileInput"))
      .toHaveTextContent("foo.txt;foo.txt")
  })

  test("should render files with format", async () => {
    await render(
      <FileInput
        data-testid="fileInput"
        format={({ name }) => name.substring(0, name.indexOf("."))}
        multiple
        placeholder="multiple"
      />,
    )
    const file = new File(["foo"], "foo.txt", { type: "text/plain" })

    changeFiles([file, file])

    await expect
      .element(page.getByTestId("fileInput"))
      .toHaveTextContent("foo,foo")
  })

  test("should render files with children", async () => {
    await render(
      <FileInput data-testid="fileInput" multiple>
        {(files) => <div>Selected: {files?.length ?? 0}</div>}
      </FileInput>,
    )
    const file = new File(["foo"], "foo.txt", { type: "text/plain" })

    changeFiles([file, file])

    await expect
      .element(page.getByTestId("fileInput"))
      .toHaveTextContent("Selected: 2")
  })

  test("should be disabled", async () => {
    await render(<FileInput disabled />)
    expect(getInput()).toBeDisabled()
  })

  test("should be read only", async () => {
    await render(<FileInput readOnly />)
    expect(getInput()).toHaveAttribute("readonly")
  })

  test("should be invalid", async () => {
    await render(<FileInput invalid />)
    expect(getInput()).toHaveAttribute("aria-invalid", "true")
  })

  test("should receive the resetRef, which resets files when invoked", async () => {
    const resetRef: { current: (() => void) | null } = { current: null }
    let files: File[] | undefined = []
    const onChange = vi.fn((newFiles: File[] | undefined) => {
      files = newFiles
    })

    await render(<FileInput multiple resetRef={resetRef} onChange={onChange} />)

    const file1 = new File(["hoge"], "hoge.txt", { type: "text/plain" })
    const file2 = new File(["foo"], "foo.png", {
      type: "image/png",
    })
    const file3 = new File(["bar"], "bar.pdf", {
      type: "application/pdf",
    })

    changeFiles([file1, file2, file3])

    expect(files).toHaveLength(3)
    expect(files[0]).toStrictEqual(file1)
    expect(files[1]).toStrictEqual(file2)
    expect(files[2]).toStrictEqual(file3)
    expect(resetRef).toBeTruthy()
    expect(typeof resetRef.current).toBe("function")

    resetRef.current?.()

    await expect.poll(() => files).toBeFalsy()
    expect(onChange).toHaveBeenCalledTimes(2)
  })

  test("should receive the files onChange", async () => {
    let files: File[] | undefined = []
    const onChange = vi.fn((newFiles: File[] | undefined) => {
      files = newFiles
    })

    await render(<FileInput multiple onChange={onChange} />)

    const file = new File(["foo"], "foo.txt", { type: "text/plain" })

    changeFiles([file, file, file])

    expect(onChange).toHaveBeenCalledTimes(1)
    expect(files).toHaveLength(3)
    files.forEach((value: File) => expect(value).toStrictEqual(file))
  })

  test("should not show files in the onChange function if no files are present", async () => {
    let value: any = null
    const onChange = (val: any) => {
      value = val
    }

    await render(<FileInput onChange={onChange} />)

    const file = new File(["foo"], "foo.txt", { type: "text/plain" })

    changeFiles([file, file, file])
    changeFiles(null)

    expect(value).toBeFalsy()
  })

  test("should work with custom component for displaying files", async () => {
    let files: any = []

    await render(
      <div>
        <FileInput
          component={({ index, value }) => {
            files.push(value)

            return (
              <div>
                <div data-testid={"index " + index}>{index}</div>
                <div data-testid={"name" + index}>{value.name}</div>
                <div data-testid={"type" + index}>{value.type}</div>
              </div>
            )
          }}
          multiple
        />
      </div>,
    )

    const file1 = new File(["foo"], "foo.txt", { type: "text/plain" })
    const file2 = new File(["foo bar"], "foo-bar.png", {
      type: "image/png",
    })

    changeFiles([file1, file2])

    await expect.element(page.getByText("foo.txt")).toBeInTheDocument()
    await expect.element(page.getByText("foo-bar.png")).toBeInTheDocument()
    await expect.element(page.getByText("0")).toBeInTheDocument()
    await expect.element(page.getByText("1")).toBeInTheDocument()
    await expect.element(page.getByText("text/plain")).toBeInTheDocument()
    await expect.element(page.getByText("image/png")).toBeInTheDocument()
    expect(files).toStrictEqual([file1, file2])
  })

  test("should work with custom component which returns null for displaying files", async () => {
    let files: any = []

    await render(
      <div>
        <FileInput
          component={({ value }) => {
            files.push(value)

            return null
          }}
          multiple
        />
      </div>,
    )

    const file1 = new File(["foo"], "foo.txt", { type: "text/plain" })
    const file2 = new File(["foo bar"], "foo-bar.txt", {
      type: "text/plain",
    })

    changeFiles([file1, file2])

    expect(files).toStrictEqual([file1, file2])
    await expect.element(page.getByText("foo.txt")).not.toBeInTheDocument()
    await expect.element(page.getByText("foo-bar.txt")).not.toBeInTheDocument()
  })

  test("click should not be called in the inner input element after click when disabled", async () => {
    await render(<FileInput data-testid="fileInput" disabled />)

    const input = getInput()
    const fn = vi.fn()

    input.addEventListener("click", fn)
    clickElement(page.getByTestId("fileInput").element())

    expect(fn).toHaveBeenCalledTimes(0)
  })

  test("click should not be called in the inner input element after click when readonly", async () => {
    await render(<FileInput data-testid="fileInput" readOnly />)

    const input = getInput()
    const fn = vi.fn()

    input.addEventListener("click", fn)
    clickElement(page.getByTestId("fileInput").element())

    expect(fn).toHaveBeenCalledTimes(0)
  })

  test("click should be called in the inner input element after click", async () => {
    const { user } = await render(<FileInput data-testid="fileInput" />)

    const input = getInput()
    const fn = vi.fn()

    input.addEventListener("click", fn)
    await user.click(page.getByTestId("fileInput"))

    expect(fn).toHaveBeenCalledTimes(1)
  })

  test("should merge context and user props without overwriting className, style, and event handlers", async () => {
    const onContextClick = vi.fn()
    const onUserClick = vi.fn()

    const { user } = await render(
      <InputPropsContext
        value={{
          className: "from-context",
          style: { color: "red" },
          onClick: onContextClick,
        }}
      >
        <FileInput
          className="from-user"
          style={{ backgroundColor: "blue" }}
          data-testid="fileInput"
          placeholder="placeholder"
          onClick={onUserClick}
        />
      </InputPropsContext>,
    )

    const el = page.getByTestId("fileInput")

    await expect.element(el).toHaveClass("from-context", "from-user")
    await expect.element(el).toHaveStyle({ color: "rgb(255, 0, 0)" })
    await expect.element(el).toHaveStyle({ backgroundColor: "rgb(0, 0, 255)" })

    await user.click(el)

    expect(onContextClick).toHaveBeenCalledTimes(1)
    expect(onUserClick).toHaveBeenCalledTimes(1)
  })
})

"use client"

import type { ReactNode } from "react"
import type { HTMLStyledProps, ThemeProps } from "@yamada-ui/react"
import type { FieldProps } from "../field"
import type { UseInputBorderProps } from "../input"
import type { FileInputStyle } from "./file-input.style"
import type { UseFileInputProps } from "./use-file-input"
import { cloneElement, isValidElement, useMemo } from "react"
import { createSlotComponent, mergeProps, styled } from "@yamada-ui/react"
import { useInputBorder, useInputPropsContext } from "../input"
import { Portal } from "../portal"
import { fileInputStyle } from "./file-input.style"
import { useFileInput } from "./use-file-input"

const defaultFormat: (value: File, index: number) => string = ({ name }) => name

export interface FileInputProps
  extends
    Omit<
      HTMLStyledProps<"input">,
      "children" | "defaultValue" | "onChange" | "value"
    >,
    ThemeProps<FileInputStyle>,
    UseInputBorderProps,
    FieldProps,
    Omit<UseFileInputProps, "children"> {
  /**
   * The string to separate uploaded files.
   *
   * @default ','
   */
  separator?: string
  /**
   * A callback that returns a React node.
   */
  children?: (files: File[] | undefined) => ReactNode
  /**
   * The component that displays uploaded files.
   */
  component?: (props: { index: number; value: File }) => ReactNode
  /**
   * A callback that formats the name of the uploaded file.
   */
  format?: (value: File, index: number) => string
}

const {
  PropsContext: FileInputPropsContext,
  usePropsContext: useFileInputPropsContext,
  withContext,
  withProvider,
} = createSlotComponent<FileInputProps, FileInputStyle>(
  "file-input",
  fileInputStyle,
)

export { FileInputPropsContext, useFileInputPropsContext }

/**
 * `FileInput` is a component used for users to select files.
 *
 * @see https://yamada-ui.com/docs/components/file-input
 */
export const FileInput = withProvider<"input", FileInputProps>(
  ({
    children,
    component,
    errorBorderColor,
    focusBorderColor,
    format = defaultFormat,
    placeholder,
    separator = ",",
    ...props
  }) => {
    const varProps = useInputBorder({ errorBorderColor, focusBorderColor })
    const { values, getFieldProps, getInputProps } = useFileInput(props)

    const cloneChildren = useMemo(() => {
      if (!values?.length)
        return (
          <styled.span overflow="hidden" whiteSpace="nowrap">
            {placeholder}
          </styled.span>
        )

      if (children) return children(values)

      return values.map((value, index) => {
        const last = values.length === index + 1

        if (component) {
          const node = component({ index, value })

          if (isValidElement(node)) {
            return cloneElement(node, { key: index })
          } else {
            return node
          }
        } else {
          return (
            <FileInputTag key={index}>
              {format(value, index)}
              {!last ? separator : null}
            </FileInputTag>
          )
        }
      })
    }, [children, format, placeholder, separator, component, values])

    return (
      <>
        <Portal>
          <styled.input {...getInputProps()} />
        </Portal>

        <styled.div {...varProps} {...getFieldProps()}>
          {cloneChildren}
        </styled.div>
      </>
    )
  },
  "root",
)((props) => {
  const context = useInputPropsContext()

  return mergeProps(context, props)()
})

interface FileInputTagProps extends HTMLStyledProps {}

const FileInputTag = withContext<"span", FileInputTagProps>("span", "tag")()
